"use client";
import { useState } from "react";
import { motion,useReducedMotion } from "framer-motion";
const chapters=["Context","Evidence","Decision"];
export default function ReadingIndexJourney(){const [a,setA]=useState(0);const reduced=useReducedMotion();return <div tabIndex={0} aria-label="Scrollable reading journey" onScroll={e=>{const next=Math.min(2,Math.round(e.currentTarget.scrollTop/135));setA(next)}} className="h-64 overflow-y-auto rounded-[22px] bg-[#f4f5f6] p-3 outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]"><div className="grid grid-cols-[36px_1fr] gap-3"><aside aria-hidden className="sticky top-0 h-40 rounded-xl bg-white p-2">{chapters.map((_,i)=><motion.i key={i} animate={{y:a===i&&!reduced?-4:0,opacity:a===i?1:.25}} transition={{type:"spring",stiffness:300,damping:26}} className="mb-7 block h-3 w-3 rounded-full bg-[#14b8a6]"/>)}</aside><div>{chapters.map((c,i)=><motion.section key={c} aria-labelledby={`chapter-${i}`} initial={reduced?false:{opacity:0,y:10}} whileInView={{opacity:1,y:0}} transition={{duration:.22}} className="mb-3 min-h-32 rounded-[18px] border border-[#ececee] bg-white p-4"><p className="text-xs font-bold text-[#4a4a4f]">0{i+1}</p><h2 id={`chapter-${i}`} className="mt-2 text-lg font-black text-[#111]">{c}</h2><p className="mt-2 text-xs text-[#4a4a4f]">A measured reading checkpoint with enough space to scroll.</p></motion.section>)}</div></div><p aria-live="polite" className="sr-only">Reading {chapters[a]}.</p></div>}
